import java.util.*;class SlidingWindowMax{public static void main(String[]a){Scanner s=new Scanner(System.in);int n=s.nextInt();int[] arr=new int[n];for(int i=0;i<n;i++)arr[i]=s.nextInt();int k=s.nextInt();Deque<Integer>d=new ArrayDeque<>();for(int i=0;i<n;i++){while(!d.isEmpty()&&d.peekFirst()<=i-k)d.pollFirst();while(!d.isEmpty()&&arr[d.peekLast()]<=arr[i])d.pollLast();d.offerLast(i);if(i>=k-1)System.out.print(arr[d.peekFirst()]+" ");}}}